diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 255ce6973a16..4c8c63a4db9f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -1538,6 +1538,32 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   if (II->isCommutative()) {
     if (CallInst *NewCall = canonicalizeConstantArg0ToArg1(CI))
       return NewCall;
+
+    // (A ? B : C) op (A ? C : B) -> B op C
+    // For commutative intrinsics where both operands are selects with the same
+    // condition and swapped true/false values.
+    Value *A, *B, *C, *D, *E, *F;
+    if (match(II->getArgOperand(0),
+              m_Select(m_Value(A), m_Value(B), m_Value(C))) &&
+        match(II->getArgOperand(1),
+              m_Select(m_Value(D), m_Value(E), m_Value(F))) &&
+        A == D && B == F && C == E) {
+      SmallVector<Value *, 4> NewArgs;
+      NewArgs.push_back(B);
+      NewArgs.push_back(C);
+      for (unsigned i = 2; i < II->arg_size(); ++i)
+        NewArgs.push_back(II->getArgOperand(i));
+
+      SmallVector<Type *, 4> Types;
+      for (Type *T : II->getFunctionType()->params())
+        Types.push_back(T);
+
+      CallInst *NewCall = Builder.CreateIntrinsic(
+          II->getIntrinsicID(), Types, NewArgs, II);
+      if (isa<FPMathOperator>(NewCall))
+        NewCall->copyFastMathFlags(II);
+      return NewCall;
+    }
   }

   // Unused constrained FP intrinsic calls may have declared side effect, which
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..53e18da72730 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1143,6 +1143,22 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
       else if (True && !False)
         False = Builder.CreateBinOp(Opcode, C, F);
     }
+
+    // If both arms of the select simplify to the same value, just return it.
+    if (True && False && True == False)
+      return True;
+    // For commutative ops, check if the select operands are swapped:
+    // (A ? B : C) op (A ? C : B) --> B op C
+    if (!True && !False && Instruction::isCommutative(Opcode) &&
+        B == F && C == E) {
+      True = Builder.CreateBinOp(Opcode, B, C);
+      if (auto *NewI = dyn_cast<Instruction>(True)) {
+        NewI->copyIRFlags(&I);
+        if (isa<FPMathOperator>(NewI))
+          NewI->copyFastMathFlags(FMF);
+      }
+      return True;
+    }
   } else if (LHSIsSelect && LHS->hasOneUse()) {
     // (A ? B : C) op Y -> A ? (B op Y) : (C op Y)
     Cond = A;

